UIGoldHud.GOLD_HUD_PATH = "UI/Prefabs/Com"
UIGoldHud.GOLD_HUD_NAME = "GoldHUD"

function UIGoldHud:LHud()
    self._parentTrans = nil
    self._goldHUDDate = nil
    self._goldHUDTrans = nil

    ---@type LDisplayPrefab
    self._dpPrefab = nil
end

function UIGoldHud:SetDelete()
    self._isDelete = true
end

function UIGoldHud:Create(parentTrans, pb)
    self._uiCamera = LGameUI.GetUICamera()

    if not pb then
        return
    end

    self._parentTrans = parentTrans
    self._goldHUDDate = pb
    self._path = UIGoldHud.GOLD_HUD_PATH
    self._name = UIGoldHud.GOLD_HUD_NAME
    self:OnCreate()
end

function UIGoldHud:StartLoad()
    self:ClearPrefab()
    local dpPrefab = LDisplayPrefab:New()
    self._dpPrefab = dpPrefab
    dpPrefab:CreatePrefab(self._parentTrans, self._path, self._name)
    dpPrefab:SetLoadedFunction(function (dp)
        self:OnLoaded(dp)
    end)
    dpPrefab:StartLoad()
end

function UIGoldHud:OnLoaded(dp)
    if self:IsDelete() then return end

    local instTrans = dp:GetDisplayTrans()
    if instTrans then
        self._goldHUDTrans = instTrans
        self:InternalInit_curHudText()
    end

    self:PlayHUDAnimation()
end

function UIGoldHud:InternalInit_curHudText()
    if self._goldHUDDate.crit > 1 then
        self._hudTrans = CS.FindTrans(self._goldHUDTrans, "Crit")
    else
        self._hudTrans = CS.FindTrans(self._goldHUDTrans, "Small")
    end
    CS.ShowObject(self._hudTrans, true)

    self._getGoldValueTrans = CS.FindTrans(self._hudTrans, "GetGoldValue")
    self._critValueTrans = CS.FindTrans(self._hudTrans, "CritValue")
    self._goldTextTrans = CS.FindTrans(self._hudTrans, "GetGoldText")
    self._critImageTrans =self._isEnus and  CS.FindTrans(self._hudTrans, "CritImage_enus") or  CS.FindTrans(self._hudTrans, "CritImage")

    
    self._goldImageTrans = CS.FindTrans(self._hudTrans, "GoldImage")
    self._startPointTrans = CS.FindTrans(self._parentTrans, "StartPoint")
    self._upPointTrans = CS.FindTrans(self._parentTrans, "UpPoint")
    self._downPointTrans = CS.FindTrans(self._parentTrans, "DownPoint")
    self._Bg_enusTrans = CS.FindTrans(self._hudTrans, "Bg_enus")

    self._isEnus = gLGameLanguage:IsForeignVersion()
    CS.ShowObject(self._Bg_enusTrans, self._isEnus)
    CS.ShowObject(self._hudTrans, true)
    if self._getGoldValueTrans then
        self._getGoldValueText = self._getGoldValueTrans:GetComponent(typeXUIText)
    end
    if self._critValueTrans then
        self._critValueText = self._critValueTrans:GetComponent(typeXUIText)
    end
    if self._goldHUDTrans then
        self._goldHUDText = self._goldHUDTrans:GetComponent(typeXUIText)
    end
    if self._goldTextTrans then
        self._goldGetText = self._goldTextTrans:GetComponent(typeXUIText)
    end
    if self._critImageTrans then
        self:SetImageLanguage(self._critImageTrans)
        self._critImage = self._critImageTrans:GetComponent(typeUIImage)
    end
    if self._goldImageTrans then
        self._goldImage = self._goldImageTrans:GetComponent(typeUIImage)
    end
    if self._goldHUDTrans then
        self._canvasGroup = self._goldHUDTrans:GetComponent(typeofCanvasGroup)
    end

    local str = ccClientText(13010)

    self:SetXTextContent(self._goldGetText, str)

    if self._goldHUDDate.gold then
        local value = LUtil.NumberCoversion(self._goldHUDDate.gold)
        self:SetXTextContent(self._getGoldValueText, value)
    end

    if self._goldHUDDate.crit > 1 then
        CS.ShowObject(self._critImageTrans, true)
        CS.ShowObject(self._critValueText, true)
        self:SetXTextContent(self._critValueText, string.format("X%.1f", self._goldHUDDate.crit))
    end

    if self._startPointTrans then
        self._goldHUDTrans.localPosition = self._startPointTrans.localPosition
    end
end

function UIGoldHud:PlayHUDAnimation()
    local canvasGroup = self._canvasGroup
    canvasGroup.alpha = 1
    --self._goldHUDTrans.localPosition = Vector3(0,0,0)
    local large = Vector3(1.5, 1.5, 0)
    local small = Vector3(1, 1, 1)
    local time = 1
    local critTime1 = 0.2
    local critTime2 = 1.5
    local alphatTime = 0.2
    local appendIntervalTime = 0.3
    local insertTime = 0
    local tween = typeDOTween.Sequence()
    self._seqTween = tween

    --是否暴击
    if self._goldHUDDate.crit > 1 then
        insertTime = 2
        local sizeTween = self._goldHUDTrans:DOScale(large, alphatTime):SetEase(EaseOutCubic)
        tween:Append(sizeTween)
        local critTime1Tween = self._goldHUDTrans:DOLocalMove(self._downPointTrans.localPosition, critTime1)
        tween:Join(critTime1Tween)

        tween:AppendInterval(appendIntervalTime)
        local sizeTween = self._goldHUDTrans:DOScale(small, critTime2):SetEase(EaseOutCubic)
        tween:Append(sizeTween)
        local critTime2Tween = self._goldHUDTrans:DOLocalMove(self._upPointTrans.localPosition, critTime2)
        tween:Join(critTime2Tween)
    else
        insertTime = 0.7
        local timeTween = self._goldHUDTrans:DOLocalMoveY(self._upPointTrans.localPosition.y, time)
        tween:Join(timeTween)
    end

    local alphatween = CS.YXDOTweenModuleUI.DOFade(canvasGroup, 0, 0.5)
    tween:Insert(insertTime, alphatween)
    tween:OnComplete(function()
        tween = nil
        self._seqTween = nil
        self._playEnd = true

    end)
    tween:Play()
end

function UIGoldHud:IsPlayEnd()
    return self._playEnd
end

function UIGoldHud:IsDelete()
    return self._isDelete
end

function UIGoldHud:ClearPrefab()
    if self._dpPrefab then
        self._dpPrefab:Destroy()
        self._dpPrefab = nil
    end
end

function UIGoldHud:Destroy()
    self:OnDestroy()

    if self:IsDpValid() then
        if self._seqTween then
            self._seqTween:Kill(false)
            self._seqTween = nil
        end
    end
    LxNodeBase.Dispose(self)
    self._isDelete = true
    self.isReady = false
end

